import json
import logging
import subprocess
import shlex
import pika

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Allowlist of permitted commands with their allowed arguments patterns
ALLOWED_COMMANDS = {
    "generate_report": {
        "executable": "/usr/local/bin/generate_report.sh",
        "allowed_args": ["--date", "--format", "--output-dir"],
    },
    "process_data": {
        "executable": "/usr/local/bin/process_data.py",
        "allowed_args": ["--input-file", "--batch-id"],
    },
    "cleanup": {
        "executable": "/usr/local/bin/cleanup.sh",
        "allowed_args": ["--older-than-days"],
    },
}

SAFE_OUTPUT_DIRS = ["/var/output/", "/tmp/jobs/"]


def validate_arg_value(value: str) -> bool:
    """Reject values that could be used for shell injection."""
    dangerous_chars = [";", "&", "|", "`", "$", "(", ")", "{", "}", "<", ">", "\n", "\r"]
    for char in dangerous_chars:
        if char in value:
            return False
    if ".." in value:
        return False
    return True


def build_safe_command(message: dict) -> list[str]:
    """Build a safe command list from a validated message."""
    task_name = message.get("task")
    params = message.get("params", {})

    if task_name not in ALLOWED_COMMANDS:
        raise ValueError(f"Unknown task: {task_name!r}. Allowed: {list(ALLOWED_COMMANDS.keys())}")

    task_config = ALLOWED_COMMANDS[task_name]
    cmd = [task_config["executable"]]

    for arg_name, arg_value in params.items():
        prefixed_arg = f"--{arg_name}" if not arg_name.startswith("--") else arg_name

        if prefixed_arg not in task_config["allowed_args"]:
            raise ValueError(
                f"Argument {prefixed_arg!r} not allowed for task {task_name!r}. "
                f"Allowed: {task_config['allowed_args']}"
            )

        str_value = str(arg_value)
        if not validate_arg_value(str_value):
            raise ValueError(f"Argument value {str_value!r} contains forbidden characters")

        cmd.extend([prefixed_arg, str_value])

    return cmd


def process_message(ch, method, properties, body):
    """Process a job message safely."""
    try:
        message = json.loads(body)
        logger.info("Received task: %s", message.get("task"))

        cmd = build_safe_command(message)
        logger.info("Executing safe command: %s", cmd)

        result = subprocess.run(
            cmd,
            shell=False,  # NEVER use shell=True with external input
            capture_output=True,
            text=True,
            timeout=300,
            cwd="/tmp/jobs",
            env={"PATH": "/usr/local/bin:/usr/bin", "HOME": "/tmp"},
        )

        if result.returncode == 0:
            logger.info("Task completed successfully: %s", result.stdout[:500])
            ch.basic_ack(delivery_tag=method.delivery_tag)
        else:
            logger.error("Task failed (exit %d): %s", result.returncode, result.stderr[:500])
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    except (json.JSONDecodeError, ValueError) as e:
        logger.error("Invalid message rejected: %s", e)
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except subprocess.TimeoutExpired:
        logger.error("Task timed out")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as e:
        logger.exception("Unexpected error processing message: %s", e)
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)


def main():
    credentials = pika.PlainCredentials("guest", "guest")
    connection = pika.BlockingConnection(
        pika.ConnectionParameters(host="localhost", credentials=credentials)
    )
    channel = connection.channel()

    channel.queue_declare(queue="jobs", durable=True)
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue="jobs", on_message_callback=process_message)

    logger.info("Waiting for job messages. Press CTRL+C to exit.")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        channel.stop_consuming()
    finally:
        connection.close()


if __name__ == "__main__":
    main()

